  exporterRapportPDF(rapport, type) {
    if (!rapport) {
      console.error("Aucun rapport \xE0 exporter");
      return;
    }
    try {
      const html = this.genererHTMLRapport(rapport, type);
      const fenetre = window.open("", "_blank");
      if (!fenetre) {
        throw new Error("Impossible d'ouvrir la fen\xEAtre");
      }
      fenetre.document.write(html);
      fenetre.document.close();
      fenetre.onload = () => {
        setTimeout(() => {
          fenetre.focus();
          fenetre.print();
        }, 500);
      };
    } catch (error) {
      console.error("Erreur lors de l'export PDF:", error);
    }
  }
  formatDateLong(dateString) {
    if (!dateString)
      return "";
    try {
      const date = new Date(dateString);
      return date.toLocaleDateString("fr-FR", {
        day: "2-digit",
        month: "long",
        year: "numeric"
      });
    } catch {
      return dateString;
    }
  }
  formatDateShort(dateString) {
    if (!dateString)
      return "";
    try {
      const date = new Date(dateString);
      return date.toLocaleDateString("fr-FR", {
        day: "2-digit",
        month: "short"
      });
    } catch {
      return dateString;
    }
  }
